+
+        while (!isValid) {
+          input = await question(`   Current: ${displayValue}\n   New value: `);
+
+          // Keep current if empty
+          if (!input.trim()) {
+            input = currentValue;
+          }
+
+          // Validate if validator exists
+          if (input && def.validation) {
