+
+    console.log('Providers configured:');
+    console.log(`  ${hasAnthropic ? '✅' : '❌'} Anthropic (Claude)`);
+    console.log(`  ${hasOpenRouter ? '✅' : '❌'} OpenRouter (Alternative models)`);
+    console.log(`  ⚙️  ONNX (Local inference) - always available`);
