+
+For more information: https://github.com/ruvnet/agentic-flow
+  `);
+}
+
+// If run directly
+if (import.meta.url === `file://${process.argv[1]}`) {
+  const args = process.argv.slice(2);
+  handleConfigCommand(args).catch(err => {
+    console.error(err.message);
+    process.exit(1);
+  });
+}
